const rawAnalysis = $input.first().json.text || $input.first().json.output || $input.first().json;

// Fix Double-Stringified JSON at the source
let analysis = rawAnalysis;
if (typeof rawAnalysis === 'string') {
  try {
    analysis = JSON.parse(rawAnalysis);
  } catch(e) {}
}

return [{
  json: { success: true },
  binary: {
    json_data: {
      data: Buffer.from(JSON.stringify({ analysis: analysis }, null, 2)).toString('base64'),
      mimeType: 'application/json',
      fileName: 'temp_analysis.json'
    }
  }
}];

